"""Decomposition: PCA, TruncatedSVD."""
import numpy as np
from sklearn.base import BaseEstimator, TransformerMixin


class PCA(BaseEstimator, TransformerMixin):
    def __init__(self, n_components=None, *, copy=True, whiten=False,
                 svd_solver='auto', tol=0.0, iterated_power='auto',
                 n_oversamples=10, power_iteration_normalizer='auto',
                 random_state=None):
        self.n_components = n_components
        self.copy = copy
        self.whiten = whiten
        self.svd_solver = svd_solver
        self.tol = tol
        self.iterated_power = iterated_power
        self.n_oversamples = n_oversamples
        self.power_iteration_normalizer = power_iteration_normalizer
        self.random_state = random_state
        self.components_ = None
        self.explained_variance_ = None
        self.explained_variance_ratio_ = None
        self.mean_ = None

    def fit(self, X, y=None):
        X = np.asarray(X, dtype=float)
        if X.ndim == 1:
            X = X.reshape(-1, 1)
        n_samples, n_features = X.shape
        self.mean_ = np.mean(X, axis=0)
        X_centered = X - self.mean_
        # Covariance matrix
        cov = np.dot(X_centered.T, X_centered) / (n_samples - 1)
        # Eigendecomposition (eigh returns sorted ascending)
        eigenvalues, eigenvectors = np.linalg.eigh(cov)
        # Sort descending
        idx = np.argsort(eigenvalues)[::-1]
        eigenvalues = eigenvalues[idx]
        eigenvectors = eigenvectors[:, idx]
        # Select components
        n_comp = self.n_components if self.n_components is not None else n_features
        n_comp = min(n_comp, n_features)
        self.components_ = eigenvectors[:, :n_comp].T  # shape (n_components, n_features)
        self.explained_variance_ = eigenvalues[:n_comp]
        total_var = np.sum(eigenvalues)
        self.explained_variance_ratio_ = eigenvalues[:n_comp] / max(total_var, 1e-15)
        return self

    def transform(self, X):
        X = np.asarray(X, dtype=float)
        if X.ndim == 1:
            X = X.reshape(-1, 1)
        return np.dot(X - self.mean_, self.components_.T)

    def inverse_transform(self, X):
        X = np.asarray(X, dtype=float)
        if X.ndim == 1:
            X = X.reshape(1, -1)
        return np.dot(X, self.components_) + self.mean_


class TruncatedSVD(BaseEstimator, TransformerMixin):
    def __init__(self, n_components=2, *, algorithm='randomized', n_iter=5,
                 n_oversamples=10, power_iteration_normalizer='auto',
                 random_state=None, tol=0.0):
        self.n_components = n_components
        self.algorithm = algorithm
        self.n_iter = n_iter
        self.n_oversamples = n_oversamples
        self.power_iteration_normalizer = power_iteration_normalizer
        self.random_state = random_state
        self.tol = tol
        self.components_ = None
        self.explained_variance_ = None
        self.explained_variance_ratio_ = None
        self.singular_values_ = None

    def fit(self, X, y=None):
        X = np.asarray(X, dtype=float)
        if X.ndim == 1:
            X = X.reshape(-1, 1)
        U, s, Vt = np.linalg.svd(X, full_matrices=False)
        n_comp = min(self.n_components, len(s))
        self.components_ = Vt[:n_comp]
        self.singular_values_ = s[:n_comp]
        self.explained_variance_ = (s[:n_comp] ** 2) / (X.shape[0] - 1)
        total_var = np.sum(s ** 2) / (X.shape[0] - 1)
        self.explained_variance_ratio_ = self.explained_variance_ / max(total_var, 1e-15)
        return self

    def transform(self, X):
        X = np.asarray(X, dtype=float)
        if X.ndim == 1:
            X = X.reshape(-1, 1)
        return np.dot(X, self.components_.T)

    def inverse_transform(self, X):
        X = np.asarray(X, dtype=float)
        if X.ndim == 1:
            X = X.reshape(1, -1)
        return np.dot(X, self.components_)


class NMF(BaseEstimator, TransformerMixin):
    """Non-negative Matrix Factorization with multiplicative update rules."""
    def __init__(self, n_components=None, *, init=None, solver='cd',
                 beta_loss='frobenius', tol=1e-4, max_iter=200,
                 random_state=None, alpha_W=0.0, alpha_H='same',
                 l1_ratio=0.0, verbose=0, shuffle=False):
        self.n_components = n_components
        self.init = init
        self.solver = solver
        self.beta_loss = beta_loss
        self.tol = tol
        self.max_iter = max_iter
        self.random_state = random_state
        self.alpha_W = alpha_W
        self.alpha_H = alpha_H
        self.l1_ratio = l1_ratio
        self.verbose = verbose
        self.shuffle = shuffle
        self.components_ = None
        self.reconstruction_err_ = None
        self.n_iter_ = 0

    def fit(self, X, y=None):
        X = np.asarray(X, dtype=float)
        if X.ndim == 1:
            X = X.reshape(-1, 1)
        n, m = X.shape
        k = self.n_components if self.n_components is not None else m
        rng = np.random.RandomState(self.random_state)
        X = np.maximum(X, 0)
        W = np.abs(rng.randn(n, k)) + 0.1
        H = np.abs(rng.randn(k, m)) + 0.1
        eps = 1e-12
        for i in range(self.max_iter):
            # Update H
            numerator = W.T @ X
            denominator = W.T @ W @ H + eps
            H *= numerator / denominator
            # Update W
            numerator = X @ H.T
            denominator = W @ H @ H.T + eps
            W *= numerator / denominator
            self.n_iter_ = i + 1
            err = np.sqrt(np.sum((X - W @ H) ** 2))
            if err < self.tol:
                break
        self.components_ = H
        self.reconstruction_err_ = float(np.sqrt(np.sum((X - W @ H) ** 2)))
        self._W = W
        return self

    def transform(self, X):
        X = np.asarray(X, dtype=float)
        if X.ndim == 1:
            X = X.reshape(-1, 1)
        X = np.maximum(X, 0)
        n = X.shape[0]
        k = self.components_.shape[0]
        rng = np.random.RandomState(self.random_state)
        W = np.abs(rng.randn(n, k)) + 0.1
        H = self.components_
        eps = 1e-12
        for _ in range(self.max_iter):
            numerator = X @ H.T
            denominator = W @ H @ H.T + eps
            W *= numerator / denominator
        return W

    def inverse_transform(self, W):
        W = np.asarray(W, dtype=float)
        if W.ndim == 1:
            W = W.reshape(1, -1)
        return W @ self.components_


class FastICA(BaseEstimator, TransformerMixin):
    """Independent Component Analysis via deflation/parallel."""
    def __init__(self, n_components=None, *, algorithm='parallel',
                 whiten='unit-variance', fun='logcosh', fun_args=None,
                 max_iter=200, tol=1e-4, w_init=None, whiten_solver='svd',
                 random_state=None):
        self.n_components = n_components
        self.algorithm = algorithm
        self.whiten = whiten
        self.fun = fun
        self.fun_args = fun_args
        self.max_iter = max_iter
        self.tol = tol
        self.w_init = w_init
        self.whiten_solver = whiten_solver
        self.random_state = random_state
        self.components_ = None
        self.mixing_ = None
        self.mean_ = None
        self.whitening_ = None

    def _g(self, u):
        if self.fun == 'logcosh':
            alpha = 1.0
            return np.tanh(alpha * u), alpha * (1 - np.tanh(alpha * u) ** 2)
        elif self.fun == 'exp':
            exp_u2 = np.exp(-u ** 2 / 2)
            return u * exp_u2, (1 - u ** 2) * exp_u2
        else:  # cube
            return u ** 3, 3 * u ** 2

    def fit(self, X, y=None):
        self.fit_transform(X)
        return self

    def fit_transform(self, X, y=None):
        X = np.asarray(X, dtype=float)
        if X.ndim == 1:
            X = X.reshape(-1, 1)
        n, p = X.shape
        self.mean_ = X.mean(axis=0)
        X_c = X - self.mean_
        k = self.n_components if self.n_components is not None else p
        # Whitening
        if self.whiten:
            U, S, Vt = np.linalg.svd(X_c, full_matrices=False)
            S_inv = np.diag(1.0 / S[:k])
            self.whitening_ = (S_inv @ Vt[:k]) * np.sqrt(n)
            X_w = X_c @ self.whitening_.T
        else:
            X_w = X_c[:, :k]
            self.whitening_ = np.eye(k)
        # FastICA iteration
        rng = np.random.RandomState(self.random_state)
        W = rng.randn(k, k)
        # Symmetric decorrelation
        def _sym_decorrelation(W):
            eigvals, eigvecs = np.linalg.eigh(W @ W.T)
            eigvals = np.maximum(eigvals, 1e-12)
            return eigvecs @ np.diag(1.0 / np.sqrt(eigvals)) @ eigvecs.T @ W

        W = _sym_decorrelation(W)
        for _ in range(self.max_iter):
            W_old = W.copy()
            gwtx, g_prime = self._g(W @ X_w.T)
            W_new = (gwtx @ X_w) / n - (g_prime.mean(axis=1, keepdims=True) * W)
            W = _sym_decorrelation(W_new)
            if np.max(np.abs(np.abs(np.sum(W * W_old, axis=1)) - 1)) < self.tol:
                break
        self.components_ = W @ self.whitening_
        self.mixing_ = np.linalg.pinv(self.components_)
        S = X_c @ self.components_.T
        return S

    def transform(self, X):
        X = np.asarray(X, dtype=float)
        if X.ndim == 1:
            X = X.reshape(-1, 1)
        return (X - self.mean_) @ self.components_.T

    def inverse_transform(self, S):
        S = np.asarray(S, dtype=float)
        if S.ndim == 1:
            S = S.reshape(1, -1)
        return S @ self.mixing_.T + self.mean_


class KernelPCA(BaseEstimator, TransformerMixin):
    """PCA with kernel trick (RBF, linear, poly)."""
    def __init__(self, n_components=None, *, kernel='linear', gamma=None,
                 degree=3, coef0=1, kernel_params=None, alpha=1.0,
                 fit_inverse_transform=False, eigen_solver='auto', tol=0,
                 max_iter=None, iterated_power='auto', n_jobs=None,
                 remove_zero_eig=False, random_state=None, copy_X=True):
        self.n_components = n_components
        self.kernel = kernel
        self.gamma = gamma
        self.degree = degree
        self.coef0 = coef0
        self.kernel_params = kernel_params
        self.alpha = alpha
        self.fit_inverse_transform = fit_inverse_transform
        self.eigen_solver = eigen_solver
        self.tol = tol
        self.max_iter = max_iter
        self.iterated_power = iterated_power
        self.n_jobs = n_jobs
        self.remove_zero_eig = remove_zero_eig
        self.random_state = random_state
        self.copy_X = copy_X
        self.eigenvalues_ = None
        self.eigenvectors_ = None
        self.X_fit_ = None

    def _compute_kernel(self, X, Y=None):
        if Y is None:
            Y = X
        if self.kernel == 'linear':
            return X @ Y.T
        elif self.kernel == 'rbf':
            gamma = self.gamma if self.gamma is not None else 1.0 / X.shape[1]
            sq_X = np.sum(X ** 2, axis=1, keepdims=True)
            sq_Y = np.sum(Y ** 2, axis=1, keepdims=True)
            D = sq_X + sq_Y.T - 2 * X @ Y.T
            return np.exp(-gamma * D)
        elif self.kernel == 'poly':
            gamma = self.gamma if self.gamma is not None else 1.0 / X.shape[1]
            return (gamma * X @ Y.T + self.coef0) ** self.degree
        else:
            return X @ Y.T

    def fit(self, X, y=None):
        X = np.asarray(X, dtype=float)
        if X.ndim == 1:
            X = X.reshape(-1, 1)
        self.X_fit_ = X.copy()
        n = X.shape[0]
        K = self._compute_kernel(X)
        # Center kernel matrix
        one_n = np.ones((n, n)) / n
        K_c = K - one_n @ K - K @ one_n + one_n @ K @ one_n
        eigenvalues, eigenvectors = np.linalg.eigh(K_c)
        idx = np.argsort(eigenvalues)[::-1]
        eigenvalues = eigenvalues[idx]
        eigenvectors = eigenvectors[:, idx]
        k = self.n_components if self.n_components is not None else n
        k = min(k, n)
        if self.remove_zero_eig:
            mask = eigenvalues[:k] > self.tol
            k = max(int(np.sum(mask)), 1)
        self.eigenvalues_ = eigenvalues[:k]
        self.eigenvectors_ = eigenvectors[:, :k]
        self._K_fit_rows_mean = K.mean(axis=0)
        self._K_fit_mean = K.mean()
        return self

    def transform(self, X):
        X = np.asarray(X, dtype=float)
        if X.ndim == 1:
            X = X.reshape(-1, 1)
        K = self._compute_kernel(X, self.X_fit_)
        K_c = K - K.mean(axis=1, keepdims=True) - self._K_fit_rows_mean + self._K_fit_mean
        alphas = self.eigenvectors_
        lam = np.maximum(self.eigenvalues_, 1e-12)
        return K_c @ alphas / np.sqrt(lam)

    def fit_transform(self, X, y=None):
        self.fit(X, y)
        lam = np.maximum(self.eigenvalues_, 1e-12)
        return self.eigenvectors_ * np.sqrt(lam)


class IncrementalPCA(BaseEstimator, TransformerMixin):
    """PCA computed incrementally in batches."""
    def __init__(self, n_components=None, *, whiten=False, copy=True,
                 batch_size=None):
        self.n_components = n_components
        self.whiten = whiten
        self.copy = copy
        self.batch_size = batch_size
        self.components_ = None
        self.explained_variance_ = None
        self.explained_variance_ratio_ = None
        self.mean_ = None
        self.var_ = None
        self.n_samples_seen_ = 0
        self.singular_values_ = None

    def fit(self, X, y=None):
        X = np.asarray(X, dtype=float)
        if X.ndim == 1:
            X = X.reshape(-1, 1)
        n, p = X.shape
        batch_size = self.batch_size if self.batch_size is not None else max(5 * p, 100)
        self.n_samples_seen_ = 0
        self.mean_ = None
        self.components_ = None
        for start in range(0, n, batch_size):
            batch = X[start:start + batch_size]
            self.partial_fit(batch)
        return self

    def partial_fit(self, X, y=None):
        X = np.asarray(X, dtype=float)
        if X.ndim == 1:
            X = X.reshape(-1, 1)
        n_batch, p = X.shape
        n_comp = self.n_components if self.n_components is not None else p
        n_comp = min(n_comp, p)
        if self.n_samples_seen_ == 0:
            self.mean_ = np.zeros(p)
            self.var_ = np.zeros(p)
        old_n = self.n_samples_seen_
        new_n = old_n + n_batch
        batch_mean = X.mean(axis=0)
        batch_var = X.var(axis=0)
        # Update running mean
        new_mean = (old_n * self.mean_ + n_batch * batch_mean) / new_n
        # Update running variance (Welford)
        new_var = ((old_n * (self.var_ + (self.mean_ - new_mean) ** 2) +
                    n_batch * (batch_var + (batch_mean - new_mean) ** 2)) / new_n)
        X_centered = X - new_mean
        if self.components_ is not None:
            # Augment with previous components weighted by singular values
            mean_correction = np.sqrt(old_n * n_batch / new_n) * (self.mean_ - batch_mean)
            X_aug = np.vstack([self.singular_values_.reshape(-1, 1) * self.components_,
                               X_centered,
                               mean_correction.reshape(1, -1)])
        else:
            X_aug = X_centered
        U, S, Vt = np.linalg.svd(X_aug, full_matrices=False)
        self.components_ = Vt[:n_comp]
        self.singular_values_ = S[:n_comp]
        self.explained_variance_ = (S[:n_comp] ** 2) / (new_n - 1)
        total_var = np.sum(new_var)
        self.explained_variance_ratio_ = self.explained_variance_ / max(total_var, 1e-15)
        self.mean_ = new_mean
        self.var_ = new_var
        self.n_samples_seen_ = new_n
        return self

    def transform(self, X):
        X = np.asarray(X, dtype=float)
        if X.ndim == 1:
            X = X.reshape(-1, 1)
        X_centered = X - self.mean_
        result = X_centered @ self.components_.T
        if self.whiten:
            result /= np.sqrt(np.maximum(self.explained_variance_, 1e-12))
        return result

    def inverse_transform(self, X):
        X = np.asarray(X, dtype=float)
        if X.ndim == 1:
            X = X.reshape(1, -1)
        if self.whiten:
            X = X * np.sqrt(np.maximum(self.explained_variance_, 1e-12))
        return X @ self.components_ + self.mean_


class LatentDirichletAllocation(BaseEstimator, TransformerMixin):
    """Simplified online variational LDA for topic modelling."""
    def __init__(self, n_components=10, *, doc_topic_prior=None,
                 topic_word_prior=None, learning_method='batch',
                 learning_decay=0.7, learning_offset=10.0, max_iter=10,
                 batch_size=128, evaluate_every=-1, total_samples=1e6,
                 perp_tol=1e-1, mean_change_tol=1e-3,
                 max_doc_update_iter=100, n_jobs=None, verbose=0,
                 random_state=None):
        self.n_components = n_components
        self.doc_topic_prior = doc_topic_prior
        self.topic_word_prior = topic_word_prior
        self.learning_method = learning_method
        self.learning_decay = learning_decay
        self.learning_offset = learning_offset
        self.max_iter = max_iter
        self.batch_size = batch_size
        self.evaluate_every = evaluate_every
        self.total_samples = total_samples
        self.perp_tol = perp_tol
        self.mean_change_tol = mean_change_tol
        self.max_doc_update_iter = max_doc_update_iter
        self.n_jobs = n_jobs
        self.verbose = verbose
        self.random_state = random_state
        self.components_ = None
        self.exp_dirichlet_component_ = None

    def _e_step(self, X, components):
        n_docs = X.shape[0]
        k = self.n_components
        alpha = self.doc_topic_prior if self.doc_topic_prior is not None else 1.0 / k
        gamma = np.ones((n_docs, k))
        for _ in range(self.max_doc_update_iter):
            gamma_old = gamma.copy()
            # E[log(theta)]
            dig_gamma = gamma - 1.0  # simplified proxy for digamma
            dig_gamma = np.maximum(dig_gamma, 1e-10)
            exp_dig = dig_gamma / dig_gamma.sum(axis=1, keepdims=True)
            gamma = alpha + (exp_dig * (X @ components.T))
            if np.mean(np.abs(gamma - gamma_old)) < self.mean_change_tol:
                break
        return gamma

    def fit(self, X, y=None):
        X = np.asarray(X, dtype=float)
        if X.ndim == 1:
            X = X.reshape(-1, 1)
        X = np.maximum(X, 0)
        n, vocab = X.shape
        k = self.n_components
        rng = np.random.RandomState(self.random_state)
        eta = self.topic_word_prior if self.topic_word_prior is not None else 1.0 / k
        self.components_ = rng.gamma(100.0, 1.0 / 100.0, (k, vocab))
        for iteration in range(self.max_iter):
            gamma = self._e_step(X, self.components_)
            # M-step
            self.components_ = eta + gamma.T @ X
        # Normalise
        self.exp_dirichlet_component_ = (self.components_ /
                                          self.components_.sum(axis=1, keepdims=True))
        return self

    def transform(self, X):
        X = np.asarray(X, dtype=float)
        if X.ndim == 1:
            X = X.reshape(-1, 1)
        X = np.maximum(X, 0)
        gamma = self._e_step(X, self.components_)
        return gamma / gamma.sum(axis=1, keepdims=True)

    def fit_transform(self, X, y=None):
        self.fit(X, y)
        return self.transform(X)


class SparsePCA(BaseEstimator, TransformerMixin):
    """PCA with sparse components via elastic net."""
    def __init__(self, n_components=None, *, alpha=1, ridge_alpha=0.01,
                 max_iter=1000, tol=1e-8, method='lars', n_jobs=None,
                 U_init=None, V_init=None, verbose=False, random_state=None):
        self.n_components = n_components
        self.alpha = alpha
        self.ridge_alpha = ridge_alpha
        self.max_iter = max_iter
        self.tol = tol
        self.method = method
        self.n_jobs = n_jobs
        self.U_init = U_init
        self.V_init = V_init
        self.verbose = verbose
        self.random_state = random_state
        self.components_ = None
        self.error_ = None
        self.mean_ = None

    def fit(self, X, y=None):
        X = np.asarray(X, dtype=float)
        if X.ndim == 1:
            X = X.reshape(-1, 1)
        n, p = X.shape
        self.mean_ = X.mean(axis=0)
        X_c = X - self.mean_
        k = self.n_components if self.n_components is not None else p
        k = min(k, p, n)
        rng = np.random.RandomState(self.random_state)
        # Initialise via SVD
        U, S, Vt = np.linalg.svd(X_c, full_matrices=False)
        V = Vt[:k].T  # (p, k)
        for _ in range(self.max_iter):
            V_old = V.copy()
            # Update codes
            codes = X_c @ V @ np.linalg.inv(V.T @ V + self.ridge_alpha * np.eye(k))
            # Update dictionary with L1 sparsity
            for j in range(k):
                atom = X_c.T @ codes[:, j]
                norm_code = codes[:, j] @ codes[:, j]
                if norm_code > 0:
                    atom = atom / norm_code
                # Soft threshold
                atom = np.sign(atom) * np.maximum(np.abs(atom) - self.alpha / max(norm_code, 1e-10), 0)
                norm_a = np.linalg.norm(atom)
                if norm_a > 0:
                    V[:, j] = atom / norm_a
                else:
                    V[:, j] = atom
            if np.max(np.abs(V - V_old)) < self.tol:
                break
        self.components_ = V.T  # (k, p)
        self.error_ = [float(np.sum((X_c - codes @ V.T) ** 2))]
        return self

    def transform(self, X):
        X = np.asarray(X, dtype=float)
        if X.ndim == 1:
            X = X.reshape(-1, 1)
        X_c = X - self.mean_
        k = self.components_.shape[0]
        V = self.components_.T
        codes = X_c @ V @ np.linalg.inv(V.T @ V + self.ridge_alpha * np.eye(k))
        return codes

    def fit_transform(self, X, y=None):
        self.fit(X, y)
        return self.transform(X)


class FactorAnalysis(BaseEstimator, TransformerMixin):
    """EM-based factor analysis."""
    def __init__(self, n_components=None, *, tol=1e-2, copy=True,
                 max_iter=1000, noise_variance_init=None,
                 svd_method='randomized', iterated_power=3, rotation=None,
                 random_state=0):
        self.n_components = n_components
        self.tol = tol
        self.copy = copy
        self.max_iter = max_iter
        self.noise_variance_init = noise_variance_init
        self.svd_method = svd_method
        self.iterated_power = iterated_power
        self.rotation = rotation
        self.random_state = random_state
        self.components_ = None
        self.noise_variance_ = None
        self.mean_ = None
        self.loglike_ = None

    def fit(self, X, y=None):
        X = np.asarray(X, dtype=float)
        if X.ndim == 1:
            X = X.reshape(-1, 1)
        n, p = X.shape
        self.mean_ = X.mean(axis=0)
        X_c = X - self.mean_
        k = self.n_components if self.n_components is not None else p
        k = min(k, p)
        # Initialise noise variance
        if self.noise_variance_init is not None:
            psi = np.array(self.noise_variance_init, dtype=float)
        else:
            psi = np.var(X_c, axis=0)
        # Initialise loadings from SVD
        U, S, Vt = np.linalg.svd(X_c, full_matrices=False)
        W = (Vt[:k].T * S[:k] / np.sqrt(n))
        loglike = []
        for iteration in range(self.max_iter):
            # E-step: posterior over latent factors
            psi_safe = np.maximum(psi, 1e-12)
            Psi_inv = np.diag(1.0 / psi_safe)
            M = W.T @ Psi_inv @ W + np.eye(k)
            try:
                M_inv = np.linalg.inv(M)
            except np.linalg.LinAlgError:
                M_inv = np.linalg.pinv(M)
            Ez = X_c @ Psi_inv @ W @ M_inv.T  # (n, k)
            Ezz = n * M_inv + Ez.T @ Ez
            # M-step
            W_new = (X_c.T @ Ez) @ np.linalg.inv(Ezz)
            psi_new = np.diag(X_c.T @ X_c - W_new @ Ez.T @ X_c) / n
            psi_new = np.maximum(psi_new, 1e-12)
            # Log-likelihood (simplified)
            diff_w = np.max(np.abs(W_new - W))
            W = W_new
            psi = psi_new
            if diff_w < self.tol:
                break
        self.components_ = W.T  # (k, p)
        self.noise_variance_ = psi
        self.loglike_ = loglike
        self.n_iter_ = iteration + 1
        return self

    def transform(self, X):
        X = np.asarray(X, dtype=float)
        if X.ndim == 1:
            X = X.reshape(-1, 1)
        X_c = X - self.mean_
        W = self.components_.T  # (p, k)
        psi_safe = np.maximum(self.noise_variance_, 1e-12)
        Psi_inv = np.diag(1.0 / psi_safe)
        k = self.components_.shape[0]
        M_inv = np.linalg.inv(W.T @ Psi_inv @ W + np.eye(k))
        return X_c @ Psi_inv @ W @ M_inv.T

    def fit_transform(self, X, y=None):
        self.fit(X, y)
        return self.transform(X)


class DictionaryLearning(BaseEstimator, TransformerMixin):
    """Dictionary learning via alternating minimization."""
    def __init__(self, n_components=None, *, alpha=1, max_iter=1000,
                 tol=1e-8, fit_algorithm='lars', transform_algorithm='omp',
                 transform_n_nonzero_coefs=None, transform_alpha=None,
                 n_jobs=None, code_init=None, dict_init=None, verbose=False,
                 split_sign=False, random_state=None, positive_code=False,
                 positive_dict=False, transform_max_iter=1000):
        self.n_components = n_components
        self.alpha = alpha
        self.max_iter = max_iter
        self.tol = tol
        self.fit_algorithm = fit_algorithm
        self.transform_algorithm = transform_algorithm
        self.transform_n_nonzero_coefs = transform_n_nonzero_coefs
        self.transform_alpha = transform_alpha
        self.n_jobs = n_jobs
        self.code_init = code_init
        self.dict_init = dict_init
        self.verbose = verbose
        self.split_sign = split_sign
        self.random_state = random_state
        self.positive_code = positive_code
        self.positive_dict = positive_dict
        self.transform_max_iter = transform_max_iter
        self.components_ = None
        self.error_ = None

    def _sparse_encode(self, X, dictionary):
        """Encode X with dictionary using OMP-style greedy pursuit."""
        n, p = X.shape
        k = dictionary.shape[0]
        n_nonzero = self.transform_n_nonzero_coefs
        if n_nonzero is None:
            n_nonzero = max(1, k // 10)
        codes = np.zeros((n, k))
        for i in range(n):
            residual = X[i].copy()
            active = []
            for _ in range(n_nonzero):
                corr = np.abs(dictionary @ residual)
                for a in active:
                    corr[a] = -1
                j = int(np.argmax(corr))
                active.append(j)
                D_active = dictionary[active].T
                coefs = np.linalg.lstsq(D_active, X[i], rcond=None)[0]
                residual = X[i] - D_active @ coefs
            for idx_a, feat_idx in enumerate(active):
                codes[i, feat_idx] = coefs[idx_a]
        if self.positive_code:
            codes = np.maximum(codes, 0)
        return codes

    def fit(self, X, y=None):
        X = np.asarray(X, dtype=float)
        if X.ndim == 1:
            X = X.reshape(-1, 1)
        n, p = X.shape
        k = self.n_components if self.n_components is not None else p
        rng = np.random.RandomState(self.random_state)
        if self.dict_init is not None:
            D = np.asarray(self.dict_init, dtype=float).copy()
        else:
            D = rng.randn(k, p)
            norms = np.linalg.norm(D, axis=1, keepdims=True)
            D /= np.maximum(norms, 1e-10)
        errors = []
        for iteration in range(self.max_iter):
            # Sparse coding step
            codes = self._sparse_encode(X, D)
            # Dictionary update step
            for j in range(k):
                idx = np.where(np.abs(codes[:, j]) > 1e-12)[0]
                if len(idx) == 0:
                    continue
                # Remove contribution of atom j
                codes_j = codes[idx].copy()
                codes_j[:, j] = 0
                residual = X[idx] - codes_j @ D
                atom = residual.T @ codes[idx, j]
                norm = np.linalg.norm(atom)
                if norm > 1e-10:
                    D[j] = atom / norm
                if self.positive_dict:
                    D[j] = np.maximum(D[j], 0)
                    norm = np.linalg.norm(D[j])
                    if norm > 1e-10:
                        D[j] /= norm
            err = float(np.sum((X - codes @ D) ** 2))
            errors.append(err)
            if iteration > 0 and abs(errors[-2] - errors[-1]) < self.tol:
                break
        self.components_ = D
        self.error_ = errors
        return self

    def transform(self, X):
        X = np.asarray(X, dtype=float)
        if X.ndim == 1:
            X = X.reshape(-1, 1)
        return self._sparse_encode(X, self.components_)

    def fit_transform(self, X, y=None):
        self.fit(X, y)
        return self.transform(X)


class MiniBatchNMF(BaseEstimator, TransformerMixin):
    """Online / mini-batch Non-negative Matrix Factorization."""
    def __init__(self, n_components=None, *, init=None, solver='cd',
                 beta_loss='frobenius', tol=1e-4, max_iter=200,
                 random_state=None, alpha_W=0.0, alpha_H='same',
                 l1_ratio=0.0, verbose=0, shuffle=False, batch_size=1024):
        self.n_components = n_components
        self.init = init
        self.solver = solver
        self.beta_loss = beta_loss
        self.tol = tol
        self.max_iter = max_iter
        self.random_state = random_state
        self.alpha_W = alpha_W
        self.alpha_H = alpha_H
        self.l1_ratio = l1_ratio
        self.verbose = verbose
        self.shuffle = shuffle
        self.batch_size = batch_size
        self.components_ = None
        self.reconstruction_err_ = None
        self.n_iter_ = 0

    def fit(self, X, y=None):
        X = np.asarray(X, dtype=float)
        if X.ndim == 1:
            X = X.reshape(-1, 1)
        X = np.maximum(X, 0)
        n, m = X.shape
        k = self.n_components if self.n_components is not None else m
        rng = np.random.RandomState(self.random_state)
        H = np.abs(rng.randn(k, m)) + 0.1
        eps = 1e-12
        for iteration in range(self.max_iter):
            indices = np.arange(n)
            if self.shuffle:
                rng.shuffle(indices)
            for start in range(0, n, self.batch_size):
                batch_idx = indices[start:start + self.batch_size]
                X_batch = X[batch_idx]
                n_b = X_batch.shape[0]
                # Compute W for this batch
                W_batch = np.abs(rng.randn(n_b, k)) + 0.1
                for _ in range(20):
                    num = X_batch @ H.T
                    den = W_batch @ H @ H.T + eps
                    W_batch *= num / den
                # Update H using this batch
                num = W_batch.T @ X_batch
                den = W_batch.T @ W_batch @ H + eps
                H *= num / den
            self.n_iter_ = iteration + 1
        self.components_ = H
        # Final W for reconstruction error
        W_full = np.abs(rng.randn(n, k)) + 0.1
        for _ in range(30):
            num = X @ H.T
            den = W_full @ H @ H.T + eps
            W_full *= num / den
        self.reconstruction_err_ = float(np.sqrt(np.sum((X - W_full @ H) ** 2)))
        return self

    def transform(self, X):
        X = np.asarray(X, dtype=float)
        if X.ndim == 1:
            X = X.reshape(-1, 1)
        X = np.maximum(X, 0)
        n = X.shape[0]
        k = self.components_.shape[0]
        H = self.components_
        rng = np.random.RandomState(self.random_state)
        W = np.abs(rng.randn(n, k)) + 0.1
        eps = 1e-12
        for _ in range(self.max_iter):
            num = X @ H.T
            den = W @ H @ H.T + eps
            W *= num / den
        return W

    def inverse_transform(self, W):
        W = np.asarray(W, dtype=float)
        if W.ndim == 1:
            W = W.reshape(1, -1)
        return W @ self.components_
